PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?count WHERE {
  VALUES ?club {
    wd:Q32156 wd:Q154822
  }
  ?club wdt:P2997 ?count
}
ORDER BY DESC(?count)
OFFSET 1
LIMIT 1

